	"github.com/prometheus/prometheus/model/labels"
)

// Matcher represents a label matcher.
type Matcher struct {
	Name    string `json:"name"`
	Value   string `json:"value"`
	IsRegex bool   `json:"isRegex"`
}

// Silence represents a silence for suppressing alerts.
type Silence struct {
	ID        string     `json:"id,omitempty"`
	Matchers  []Matcher  `json:"matchers"`
	StartsAt  *time.Time `json:"startsAt,omitempty"`
	EndsAt    *time.Time `json:"endsAt"`
	CreatedBy string     `json:"createdBy,omitempty"`
	Comment   string     `json:"comment"`
}

// SilenceResponse represents the response from creating a silence.
type SilenceResponse struct {
	ID string `json:"id"`
}

// BulkSilenceResponse represents the response from creating multiple silences.
type BulkSilenceResponse struct {
	IDs []string `json:"ids"`
}

// BulkSilenceError represents an error for a specific silence in a bulk request.
type BulkSilenceError struct {
	Index   int    `json:"index"`
	Message string `json:"message"`
}

// SilenceStore interface for managing silences.
type SilenceStore interface {
	Create(s *Silence) (string, error)
	Get(id string) (*Silence, error)
	Delete(id string) error
	List() []*Silence
}

// InMemorySilenceStore is a simple in-memory store for silences.
type InMemorySilenceStore struct {
	silences map[string]*Silence
	counter  int
}

// NewInMemorySilenceStore creates a new in-memory silence store.
func NewInMemorySilenceStore() *InMemorySilenceStore {
	return &InMemorySilenceStore{
		silences: make(map[string]*Silence),
		counter:  0,
	}
}

// Create stores a silence and returns its ID.
func (s *InMemorySilenceStore) Create(silence *Silence) (string, error) {
	if silence == nil {
		return "", errors.New("silence cannot be nil")
	}

	s.counter++
	id := fmt.Sprintf("silence_%d", s.counter)
	silence.ID = id
	s.silences[id] = silence
	return id, nil
}

// Get retrieves a silence by ID.
func (s *InMemorySilenceStore) Get(id string) (*Silence, error) {
	silence, exists := s.silences[id]
	if !exists {
		return nil, fmt.Errorf("silence not found: %s", id)
	}
	return silence, nil
}

// Delete removes a silence by ID.
func (s *InMemorySilenceStore) Delete(id string) error {
	if _, exists := s.silences[id]; !exists {
		return fmt.Errorf("silence not found: %s", id)
	}
	delete(s.silences, id)
	return nil
}

// List returns all silences.
func (s *InMemorySilenceStore) List() []*Silence {
	result := make([]*Silence, 0, len(s.silences))
	for _, silence := range s.silences {
		result = append(result, silence)
	}
	return result
}

// validateSilence performs validation on a silence.
func validateSilence(s *Silence) error {
	if s == nil {
		return errors.New("silence cannot be nil")
	}

	if len(s.Matchers) == 0 {
		return errors.New("at least one matcher is required")
	}

	for i, m := range s.Matchers {
		if m.Name == "" {
			return fmt.Errorf("matcher %d: name is required", i)
		}
		if m.Value == "" {
			return fmt.Errorf("matcher %d: value is required", i)
		}
		// Validate label name
		if !labels.IsValidLabelName(labels.LabelName(m.Name)) {
			return fmt.Errorf("matcher %d: invalid label name %q", i, m.Name)
		}
	}

	if s.EndsAt == nil {
		return errors.New("endsAt is required")
	}

	if s.StartsAt != nil && s.EndsAt != nil && s.StartsAt.After(*s.EndsAt) {
		return errors.New("startsAt must be before endsAt")
	}

	if s.Comment == "" {
		return errors.New("comment is required")
	}

	return nil
}

