	}

	id, err := silenceStore.Create(&silence)
	if err != nil {
		return apiFuncResult{nil, &apiError{errorInternal, err}, nil, nil}
	}

	return apiFuncResult{&SilenceResponse{ID: id}, nil, nil, nil}
}

// postSilencesBulk handles POST requests for creating multiple silences atomically.
func (api *API) postSilencesBulk(r *http.Request) apiFuncResult {
	body, err := io.ReadAll(r.Body)
	if err != nil {
		return apiFuncResult{nil, &apiError{errorBadData, errors.New("unable to read body")}, nil, nil}
	}

	var silences []Silence
	if err := json.Unmarshal(body, &silences); err != nil {
		return apiFuncResult{nil, &apiError{errorBadData, fmt.Errorf("invalid JSON: %w", err)}, nil, nil}
	}

	if len(silences) == 0 {
		return apiFuncResult{&BulkSilenceResponse{IDs: []string{}}, nil, nil, nil}
	}

	// Validate all silences before creating any (atomic semantics)
	validationErrors := make([]BulkSilenceError, 0)
	for i, silence := range silences {
		if err := validateSilence(&silence); err != nil {
			validationErrors = append(validationErrors, BulkSilenceError{
				Index:   i,
				Message: err.Error(),
			})
		}
	}

	// If there are validation errors, return them all
	if len(validationErrors) > 0 {
		errorData := map[string]interface{}{
			"errors": validationErrors,
		}
		return apiFuncResult{errorData, &apiError{errorBadData, errors.New("validation failed for one or more silences")}, nil, nil}
	}

